"use client";

import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import styles from "./Section2Overlay.module.css";

gsap.registerPlugin(ScrollTrigger);

export default function Section2Overlay() {
  const headingRef = useRef<HTMLHeadingElement>(null);
  const bodyRef    = useRef<HTMLParagraphElement>(null);
  const ctaRef     = useRef<HTMLAnchorElement>(null);
  const dotRef     = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: "#section-2",
        start: "top 60%",
        end: "top 20%",
        toggleActions: "play none none reverse",
      },
    });

    tl.fromTo(headingRef.current,
      { opacity: 0, y: 40, filter: "blur(8px)" },
      { opacity: 1, y: 0, filter: "blur(0px)", duration: 1.0, ease: "power3.out" }
    )
    .fromTo(bodyRef.current,
      { opacity: 0, y: 20 },
      { opacity: 1, y: 0, duration: 0.8, ease: "power2.out" },
      "-=0.5"
    )
    .fromTo(ctaRef.current,
      { opacity: 0, y: 12 },
      { opacity: 1, y: 0, duration: 0.6, ease: "power2.out" },
      "-=0.4"
    )
    .fromTo(dotRef.current,
      { opacity: 0, scaleY: 0 },
      { opacity: 1, scaleY: 1, duration: 0.5, ease: "power2.out" },
      "-=0.2"
    );
  }, []);

  return (
    <div className={styles.wrapper}>
      {/* Content pinned to bottom — sphere shows through canvas above */}
      <div className={styles.content}>
        <h2 ref={headingRef} className={styles.heading}>
          Mục đích
        </h2>

        <p ref={bodyRef} className={styles.body}>
          Leaders Talk tập hợp những nhà lãnh đạo tầm nhìn nhất thế giới
          trong một hệ sinh thái ý tưởng sống động — nơi mỗi ý tưởng được
          rèn giũa từ tiềm năng và hội tụ thành hiện thực.
        </p>

        <a ref={ctaRef} href="#" className={styles.cta} id="explore-cta">
          Khám phá mạng lưới
          <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
            <path d="M2.5 7h9M8 3.5L11.5 7 8 10.5"
              stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </a>

        {/* Bottom scroll indicator */}
        <div ref={dotRef} className={styles.bottomDot}>
          <div className={styles.dotRing}>
            <div className={styles.dotInner} />
          </div>
        </div>
      </div>
    </div>
  );
}
